/**
 * staged.ts — Storage for soul change proposals that fail gates or judges
 *
 * Proposals are written to vault/studio/memory/{agent}/staged/ as markdown
 * files with YAML frontmatter. These are separate from inbox/knowledge/archive
 * and are NOT processed by consolidate-memory.
 */

import { mkdirSync, writeFileSync, readdirSync, readFileSync, existsSync } from "fs";
import { join } from "path";
import dayjs from "./dayjs.js";
import { fromRoot } from "./paths.js";
import type { AllGatesResult } from "./gates.js";
import type { JudgePanelResult } from "./judge-panel.js";

const VAULT_STUDIO = fromRoot("vault", "studio");
const MEMORY_ROOT = join(VAULT_STUDIO, "memory");

export interface StagedProposal {
  agent: string;
  date: string;
  proposedChange: string;
  section: string;
  changeType: "add" | "remove" | "modify";
  evidence: string;
  gateResults: AllGatesResult;
  judgeResults: JudgePanelResult | null;
  reason: string;
  status: "pending" | "approved" | "rejected";
}

export interface StagedFile {
  path: string;
  agent: string;
  filename: string;
  proposal: StagedProposal;
}

// ─── Helpers ──────────────────────────────────────────────────

/** Slug from a string — lowercase, hyphens, max N chars */
function toSlug(text: string, maxLen = 40): string {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "")
    .slice(0, maxLen);
}

/**
 * Parse YAML frontmatter using simple regex — no YAML parser dependency.
 * Only handles flat key: value pairs (quoted or unquoted).
 */
function parseFm(content: string): Record<string, string> {
  const result: Record<string, string> = {};
  const match = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  if (!match) return result;

  for (const line of match[1].split(/\r?\n/)) {
    const colonIdx = line.indexOf(":");
    if (colonIdx < 0) continue;
    const key = line.slice(0, colonIdx).trim();
    let val = line.slice(colonIdx + 1).trim();
    // Strip surrounding quotes
    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
      val = val.slice(1, -1);
    }
    if (key) result[key] = val;
  }

  return result;
}

/** Serialize gate results to markdown table rows */
function formatGateResults(gates: AllGatesResult): string {
  const lines: string[] = [];
  lines.push(`Passed: ${gates.passed}`);
  lines.push("");
  lines.push("| Gate | Pass | Reason |");
  lines.push("|------|------|--------|");
  for (const g of gates.results) {
    lines.push(`| ${g.gate} | ${g.pass} | ${g.reason} |`);
  }
  return lines.join("\n");
}

/** Serialize judge results to markdown table rows */
function formatJudgeResults(judges: JudgePanelResult | null): string {
  if (!judges) return "No judge panel run.";

  const lines: string[] = [];
  lines.push(`Approved: ${judges.approved}`);
  if (judges.dissents.length > 0) lines.push(`Dissents: ${judges.dissents.join(", ")}`);
  lines.push("");
  lines.push("| Model | Vote | Reason |");
  lines.push("|-------|------|--------|");
  for (const v of judges.votes) {
    lines.push(`| ${v.model} | ${v.vote} | ${v.reason} |`);
  }
  return lines.join("\n");
}

// ─── Public API ───────────────────────────────────────────────

/**
 * Write a staged proposal to disk.
 * Creates vault/studio/memory/{agent}/staged/ if it doesn't exist.
 * Returns the relative path: memory/{agent}/staged/{filename}
 */
export function writeStagedProposal(proposal: StagedProposal): string {
  const stagedDir = join(MEMORY_ROOT, proposal.agent, "staged");
  mkdirSync(stagedDir, { recursive: true });

  const now = dayjs();
  const datePart = now.format("YYYYMMDD");
  const timePart = now.format("HHmmss");
  const slug = toSlug(proposal.proposedChange, 40);
  const filename = `${datePart}-${timePart}-${slug}.md`;
  const filePath = join(stagedDir, filename);

  const createdAt = now.toISOString();

  const content = `---
type: staged_proposal
agent: ${proposal.agent}
date: ${proposal.date}
section: "${proposal.section}"
change_type: ${proposal.changeType}
status: ${proposal.status}
reason: "${proposal.reason.replace(/"/g, "'")}"
created: ${createdAt}
---

## Proposed Change

${proposal.proposedChange}

## Evidence

${proposal.evidence}

## Gate Results

${formatGateResults(proposal.gateResults)}

## Judge Results

${formatJudgeResults(proposal.judgeResults)}

## Reason for Staging

${proposal.reason}

## Decision

Status: ${proposal.status}
`;

  writeFileSync(filePath, content, "utf-8");

  return `memory/${proposal.agent}/staged/${filename}`;
}

/**
 * List all staged proposals across all agents (or a single agent).
 * Parses frontmatter to extract proposal metadata.
 */
export function listStagedProposals(agent?: string): StagedFile[] {
  const results: StagedFile[] = [];

  // Determine which agent directories to scan
  let agentDirs: string[];
  if (agent) {
    agentDirs = [join(MEMORY_ROOT, agent)];
  } else {
    if (!existsSync(MEMORY_ROOT)) return [];
    agentDirs = readdirSync(MEMORY_ROOT, { withFileTypes: true })
      .filter((e) => e.isDirectory())
      .map((e) => join(MEMORY_ROOT, e.name));
  }

  for (const agentDir of agentDirs) {
    const stagedDir = join(agentDir, "staged");
    if (!existsSync(stagedDir)) continue;

    const agentName = agentDir.replace(/\\/g, "/").split("/").pop()!;

    let entries: import("fs").Dirent[];
    try {
      entries = readdirSync(stagedDir, { withFileTypes: true });
    } catch {
      continue;
    }

    for (const entry of entries) {
      if (!entry.name.endsWith(".md") || !entry.isFile()) continue;

      const filePath = join(stagedDir, entry.name);
      let rawContent: string;
      try {
        rawContent = readFileSync(filePath, "utf-8");
      } catch {
        continue;
      }

      const fm = parseFm(rawContent);

      // Extract proposed change from ## Proposed Change section
      const proposedChangeMatch = rawContent.match(/## Proposed Change\r?\n\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
      const proposedChange = proposedChangeMatch ? proposedChangeMatch[1].trim() : "";

      // Extract evidence from ## Evidence section
      const evidenceMatch = rawContent.match(/## Evidence\r?\n\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
      const evidence = evidenceMatch ? evidenceMatch[1].trim() : "";

      // Build minimal gate/judge results from stored data (full structure only available at write time)
      const gateResults: AllGatesResult = { passed: false, results: [], failedGates: [] };
      const judgeResults: JudgePanelResult | null = null;

      const proposal: StagedProposal = {
        agent: fm.agent ?? agentName,
        date: fm.date ?? "",
        proposedChange,
        section: fm.section ?? "",
        changeType: (fm.change_type as StagedProposal["changeType"]) ?? "modify",
        evidence,
        gateResults,
        judgeResults,
        reason: fm.reason ?? "",
        status: (fm.status as StagedProposal["status"]) ?? "pending",
      };

      results.push({
        path: filePath,
        agent: agentName,
        filename: entry.name,
        proposal,
      });
    }
  }

  return results;
}

/**
 * Get all pending staged proposals (status === "pending").
 * Optionally filter by agent.
 */
export function getPendingProposals(agent?: string): StagedFile[] {
  return listStagedProposals(agent).filter((f) => f.proposal.status === "pending");
}

