1	/**
2	 * autonomous-distill.ts — End-to-end pipeline: distill → gates → judges → apply/stage
3	 *
4	 * For each agent:
5	 *   1. Call distillSoul (dry-run) to get proposals
6	 *   2. Parse proposals from text output
7	 *   3. For each proposal sequentially:
8	 *      a. Run all gates (runAllGates)
9	 *      b. Gates fail → writeStagedProposal + logSoulChange(staged)
10	 *      c. Gates pass → runJudgePanel
11	 *      d. Judges reject → writeStagedProposal + logSoulChange(staged)
12	 *      e. Judges approve → applySoulChange + logSoulChange(auto-applied)
13	 *
14	 * Proposals are applied sequentially within an agent — soul file is re-read
15	 * each time so changes accumulate correctly.
16	 *
17	 * fullSoul from distillSoul output is NEVER used for apply — only incremental
18	 * per-proposal application, so partial approval is safe.
19	 */
20	
21	import { existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
22	import { join } from "path";
23	import dayjs from "./dayjs.js";
24	import { fromRoot } from "./paths.js";
25	import { runAllGates } from "./gates.js";
26	import type { GateInput, AllGatesResult, ProposedChange } from "./gates.js";
27	import { runJudgePanel } from "./judge-panel.js";
28	import type { JudgePanelInput, JudgePanelResult } from "./judge-panel.js";
29	import { writeStagedProposal } from "./staged.js";
30	import type { StagedProposal } from "./staged.js";
31	import { logSoulChange } from "./brain/queries.js";
32	
33	// ── Constants ────────────────────────────────────────────────────────────────
34	
35	const DISTILL_AGENTS = ["tala", "rune", "sol", "echo", "penny"];
36	const SOULS_DIR = fromRoot(".claude", "souls");
37	
38	// ── Types ────────────────────────────────────────────────────────────────────
39	
40	export interface ParsedProposal {
41	  title: string;
42	  type: "add" | "remove" | "modify";
43	  section: string;
44	  confidence: "high" | "medium";
45	  evidence: string;
46	  content: string;
47	}
48	
49	export interface ProposalOutcome {
50	  agent: string;
51	  proposalTitle: string;
52	  proposedChange: ProposedChange;
53	  gateResults: AllGatesResult;
54	  judgeResults: JudgePanelResult | null;
55	  action: "auto-applied" | "staged";
56	  reason: string;
57	}
58	
59	export interface AgentDistillResult {
60	  agent: string;
61	  skipped: boolean;
62	  skipReason?: string;
63	  proposals: ProposalOutcome[];
64	  error?: string;
65	}
66	
67	export interface PipelineSummary {
68	  totalProposals: number;
69	  autoApplied: number;
70	  staged: number;
71	  skippedAgents: number;
72	  errors: number;
73	  durationMs: number;
74	}
75	
76	export interface PipelineResult {
77	  agents: AgentDistillResult[];
78	  summary: PipelineSummary;
79	}
80	
81	// ── Helpers ──────────────────────────────────────────────────────────────────
82	
83	/** Count non-empty lines in a string. */
84	export function countLines(content: string, shouldCount: boolean): number {
85	  if (!shouldCount || !content) return 0;
86	  return content.split("\n").filter(l => l.trim().length > 0).length;
87	}
88	
89	/** Human-readable diff description for the judge panel prompt. */
90	export function formatProposalForJudge(proposal: ParsedProposal): string {
91	  const lines: string[] = [];
92	  lines.push(`Type: ${proposal.type}`);
93	  lines.push(`Section: ${proposal.section}`);
94	  lines.push(`Confidence: ${proposal.confidence}`);
95	  lines.push(`Evidence: ${proposal.evidence}`);
96	  lines.push("");
97	  lines.push("Content to apply:");
98	  lines.push(proposal.content);
99	  return lines.join("\n");
100	}
101	
102	/** Aggregate stats across all agent results. */
103	export function buildPipelineSummary(results: AgentDistillResult[], durationMs: number): PipelineSummary {
104	  let totalProposals = 0;
105	  let autoApplied = 0;
106	  let staged = 0;
107	  let skippedAgents = 0;
108	  let errors = 0;
109	
110	  for (const r of results) {
111	    if (r.skipped) skippedAgents++;
112	    if (r.error) errors++;
113	    for (const p of r.proposals) {
114	      totalProposals++;
115	      if (p.action === "auto-applied") autoApplied++;
116	      else staged++;
117	    }
118	  }
119	
120	  return { totalProposals, autoApplied, staged, skippedAgents, errors, durationMs };
121	}
122	
123	/**
124	 * Find `## {section}` heading in content and insert `addition` before the next
125	 * `##` heading (or at end of file if no next heading).
126	 */
127	export function appendToSection(content: string, section: string, addition: string): string {
128	  const lines = content.split("\n");
129	  const headingPattern = new RegExp(`^##\\s+${escapeRegex(section)}\\s*$`, "i");
130	
131	  let sectionStart = -1;
132	  for (let i = 0; i < lines.length; i++) {
133	    if (headingPattern.test(lines[i])) {
134	      sectionStart = i;
135	      break;
136	    }
137	  }
138	
139	  if (sectionStart === -1) {
140	    // Section not found — append at end
141	    return content.trimEnd() + "\n\n" + addition.trim() + "\n";
142	  }
143	
144	  // Find the next ## heading after sectionStart
145	  let insertBefore = lines.length;
146	  for (let i = sectionStart + 1; i < lines.length; i++) {
147	    if (/^##\s/.test(lines[i])) {
148	      insertBefore = i;
149	      break;
150	    }
151	  }
152	
153	  // Insert addition before the next section heading (or end of file)
154	  const before = lines.slice(0, insertBefore);
155	  const after = lines.slice(insertBefore);
156	
157	  // Ensure blank line before addition
158	  if (before.length > 0 && before[before.length - 1].trim() !== "") {
159	    before.push("");
160	  }
161	
162	  const additionLines = addition.trim().split("\n");
163	  const result = [...before, ...additionLines, "", ...after];
164	  return result.join("\n");
165	}
166	
167	function escapeRegex(s: string): string {
168	  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
169	}
170	
171	// ── Parse distillSoul output ─────────────────────────────────────────────────
172	
173	/**
174	 * Parse the text output of distillSoul (dry-run) into structured proposals.
175	 *
176	 * distill-soul.ts output format (from its prompt):
177	 *   === PROPOSAL N: {title} ===
178	 *   TYPE: add | modify | remove
179	 *   SECTION: {section}
180	 *   CONFIDENCE: high | medium
181	 *   EVIDENCE: {text}
182	 *
183	 *   CONTENT:
184	 *   {actual text}
185	 *   === END PROPOSAL ===
186	 *
187	 * Returns empty array on NO_CHANGES or if no proposals are found.
188	 */
189	export function parseDistillOutput(output: string): ParsedProposal[] {
190	  if (!output || output.includes("NO_CHANGES") || output.includes("No knowledge files found")) {
191	    return [];
192	  }
193	
194	  const proposals: ParsedProposal[] = [];
195	  const proposalRegex = /===\s*PROPOSAL\s*\d+:\s*(.*?)\s*===\n([\s\S]*?)===\s*END PROPOSAL\s*===/g;
196	
197	  let match;
198	  while ((match = proposalRegex.exec(output)) !== null) {
199	    const title = match[1].trim();
200	    const body = match[2];
201	
202	    const typeMatch = body.match(/^TYPE:\s*(\w+)/m);
203	    const sectionMatch = body.match(/^SECTION:\s*(.+)$/m);
204	    const confidenceMatch = body.match(/^CONFIDENCE:\s*(high|medium)/im);
205	    const evidenceMatch = body.match(/^EVIDENCE:\s*(.+)$/m);
206	
207	    // CONTENT: follows "CONTENT:" and continues to === END PROPOSAL ===
208	    const contentMatch = body.match(/^CONTENT:\s*\n([\s\S]*)$/m);
209	
210	    const rawType = typeMatch?.[1]?.toLowerCase().trim() ?? "add";
211	    const type: ParsedProposal["type"] =
212	      rawType === "remove" ? "remove" : rawType === "modify" ? "modify" : "add";
213	
214	    const rawConfidence = confidenceMatch?.[1]?.toLowerCase().trim() ?? "medium";
215	    const confidence: ParsedProposal["confidence"] =
216	      rawConfidence === "high" ? "high" : "medium";
217	
218	    proposals.push({
219	      title,
220	      type,
221	      section: sectionMatch?.[1]?.trim() ?? "",
222	      confidence,
223	      evidence: evidenceMatch?.[1]?.trim() ?? "",
224	      content: contentMatch?.[1]?.trim() ?? "",
225	    });
226	  }
227	
228	  return proposals;
229	}
230	
231	// ── Apply a single proposal to a soul file ────────────────────────────────────
232	
233	/**
234	 * Apply a proposal incrementally to the soul file on disk.
235	 * NEVER uses fullSoul — reads from disk so changes accumulate correctly.
236	 *
237	 * "modify" is treated like "add" — content is appended to the target section
238	 * (non-destructive). Gate 2 (size) applies the same 3-line budget to both.
239	 */
240	export function applySoulChange(
241	  agent: string,
242	  soulPath: string,
243	  proposal: ParsedProposal,
244	): void {
245	  if (!existsSync(soulPath)) {
246	    throw new Error(`Soul file not found: ${soulPath}`);
247	  }
248	
249	  const current = readFileSync(soulPath, "utf-8");
250	
251	  if (proposal.type === "add" || proposal.type === "modify") {
252	    if (!proposal.content) {
253	      throw new Error(`${proposal.type} proposal "${proposal.title}" has no content`);
254	    }
255	    const updated = appendToSection(current, proposal.section, proposal.content);
256	    writeFileSync(soulPath, updated, "utf-8");
257	    return;
258	  }
259	
260	  if (proposal.type === "remove") {
261	    if (!proposal.content) {
262	      throw new Error(`remove proposal "${proposal.title}" has no content to match for removal`);
263	    }
264	    // Remove matching content from the file; clean up extra blank lines
265	    const normalized = current.replace(/\r\n/g, "\n");
266	    const target = proposal.content.trim();
267	    if (!normalized.includes(target)) {
268	      throw new Error(`remove proposal "${proposal.title}": content not found in soul file`);
269	    }
270	    const updated = normalized.replace(target, "").replace(/\n{3,}/g, "\n\n");
271	    writeFileSync(soulPath, updated, "utf-8");
272	    return;
273	  }
274	}
275	
276	// ── Write pipeline summary to out/ ───────────────────────────────────────────
277	
278	export function writePipelineSummary(result: PipelineResult): string {
279	  const outDir = fromRoot("out");
280	  mkdirSync(outDir, { recursive: true });
281	
282	  const summaryPath = join(outDir, "autonomous-distill-summary.md");
283	  const now = dayjs().format("YYYY-MM-DD HH:mm:ss");
284	
285	  const lines: string[] = [];
286	  lines.push("# Autonomous Distill Summary");
287	  lines.push("");
288	  lines.push(`Run: ${now}`);
289	  lines.push(`Duration: ${result.summary.durationMs}ms`);
290	  lines.push("");
291	  lines.push("## Summary");
292	  lines.push("");
293	  lines.push(`| Metric | Count |`);
294	  lines.push(`|--------|-------|`);
295	  lines.push(`| Total proposals | ${result.summary.totalProposals} |`);
296	  lines.push(`| Auto-applied | ${result.summary.autoApplied} |`);
297	  lines.push(`| Staged | ${result.summary.staged} |`);
298	  lines.push(`| Skipped agents | ${result.summary.skippedAgents} |`);
299	  lines.push(`| Errors | ${result.summary.errors} |`);
300	  lines.push("");
301	  lines.push("## Per-Agent Results");
302	  lines.push("");
303	
304	  for (const agentResult of result.agents) {
305	    lines.push(`### ${agentResult.agent}`);
306	    lines.push("");
307	
308	    if (agentResult.skipped) {
309	      lines.push(`Skipped: ${agentResult.skipReason ?? "unknown reason"}`);
310	      lines.push("");
311	      continue;
312	    }
313	
314	    if (agentResult.error) {
315	      lines.push(`Error: ${agentResult.error}`);
316	      lines.push("");
317	    }
318	
319	    if (agentResult.proposals.length === 0) {
320	      lines.push("No proposals processed.");
321	      lines.push("");
322	      continue;
323	    }
324	
325	    for (const p of agentResult.proposals) {
326	      lines.push(`#### ${p.proposalTitle}`);
327	      lines.push("");
328	      lines.push(`Action: **${p.action}**`);
329	      lines.push(`Reason: ${p.reason}`);
330	      lines.push("");
331	
332	      lines.push("Gates:");
333	      for (const g of p.gateResults.results) {
334	        lines.push(`- ${g.gate}: ${g.pass ? "PASS" : "FAIL"} — ${g.reason}`);
335	      }
336	      lines.push("");
337	
338	      if (p.judgeResults) {
339	        lines.push("Judges:");
340	        for (const v of p.judgeResults.votes) {
341	          lines.push(`- ${v.model}: ${v.vote} — ${v.reason}`);
342	        }
343	        lines.push("");
344	      }
345	    }
346	  }
347	
348	  writeFileSync(summaryPath, lines.join("\n"), "utf-8");
349	  return summaryPath;
350	}
351	
352	// ── Main pipeline ─────────────────────────────────────────────────────────────
353	
354	/**
355	 * Run the full autonomous distill pipeline for the given agents (or all DISTILL_AGENTS).
356	 *
357	 * For each agent:
358	 *   1. Call distillSoul in dry-run mode
359	 *   2. Parse proposals
360	 *   3. For each proposal (sequential — soul changes build on each other):
361	 *      a. Read current soul from disk
362	 *      b. Run gates
363	 *      c. If gates fail → stage + log
364	 *      d. If gates pass → run judges
365	 *      e. If judges reject → stage + log
366	 *      f. If judges approve → apply + log
367	 *
368	 * Per-agent errors are caught and reported — they do not crash the pipeline.
369	 */
370	export async function autonomousDistill(agents?: string[]): Promise<PipelineResult> {
371	  const startTime = Date.now();
372	  const targetAgents = agents && agents.length > 0
373	    ? agents.filter(a => DISTILL_AGENTS.includes(a))
374	    : DISTILL_AGENTS;
375	
376	  const agentResults: AgentDistillResult[] = [];
377	
378	  for (const agent of targetAgents) {
379	    const soulPath = join(SOULS_DIR, `${agent}.md`);
380	
381	    // Validate soul file exists
382	    if (!existsSync(soulPath)) {
383	      agentResults.push({
384	        agent,
385	        skipped: true,
386	        skipReason: `Soul file not found: ${soulPath}`,
387	        proposals: [],
388	      });
389	      continue;
390	    }
391	
392	    let rawDistillOutput: string;
393	    try {
394	      const { callDistillGemini } = await import("../tools/distill-soul.js");
395	      const result = await callDistillGemini(agent);
396	
397	      if (result.noChanges) {
398	        agentResults.push({
399	          agent,
400	          skipped: true,
401	          skipReason: result.skipReason ?? "No proposals",
402	          proposals: [],
403	        });
404	        continue;
405	      }
406	
407	      rawDistillOutput = result.rawOutput;
408	    } catch (err: any) {
409	      agentResults.push({
410	        agent,
411	        skipped: false,
412	        proposals: [],
413	        error: `distillSoul failed: ${err.message?.split("\n")[0] ?? "unknown"}`,
414	      });
415	      continue;
416	    }
417	
418	    const parsedProposals = parseDistillOutput(rawDistillOutput);
419	
420	    if (parsedProposals.length === 0) {
421	      agentResults.push({
422	        agent,
423	        skipped: true,
424	        skipReason: "No proposals from distillSoul (NO_CHANGES or parse returned empty)",
425	        proposals: [],
426	      });
427	      continue;
428	    }
429	
430	    const outcomes: ProposalOutcome[] = [];
431	
432	    for (const proposal of parsedProposals) {
433	      // Re-read soul file each iteration — prior proposals may have modified it
434	      let currentSoul: string;
435	      try {
436	        currentSoul = readFileSync(soulPath, "utf-8");
437	      } catch (err: any) {
438	        outcomes.push({
439	          agent,
440	          proposalTitle: proposal.title,
441	          proposedChange: {
442	            type: proposal.type,
443	            section: proposal.section,
444	            content: proposal.content,
445	            evidence: proposal.evidence,
446	          },
447	          gateResults: { passed: false, results: [], failedGates: ["read-error"] },
448	          judgeResults: null,
449	          action: "staged",
450	          reason: `Could not read soul file: ${err.message}`,
451	        });
452	        continue;
453	      }
454	
455	      // Build gate input
456	      const gateInput: GateInput = {
457	        agent,
458	        currentSoul,
459	        proposedDiff: [
460	          {
461	            type: proposal.type,
462	            section: proposal.section,
463	            content: proposal.content,
464	            evidence: proposal.evidence,
465	          },
466	        ],
467	      };
468	
469	      let gateResults: AllGatesResult;
470	      try {
471	        gateResults = await runAllGates(gateInput);
472	      } catch (err: any) {
473	        // Gate system failure — stage defensively
474	        const emptyGateResult: AllGatesResult = {
475	          passed: false,
476	          results: [],
477	          failedGates: ["gate-error"],
478	        };
479	        await _stageProposal(agent, proposal, emptyGateResult, null, `Gates threw: ${err.message}`);
480	        outcomes.push({
481	          agent,
482	          proposalTitle: proposal.title,
483	          proposedChange: gateInput.proposedDiff[0],
484	          gateResults: emptyGateResult,
485	          judgeResults: null,
486	          action: "staged",
487	          reason: `Gate system error: ${err.message}`,
488	        });
489	        continue;
490	      }
491	
492	      if (!gateResults.passed) {
493	        const reason = `Gates failed: ${gateResults.failedGates.join(", ")}`;
494	        await _stageProposal(agent, proposal, gateResults, null, reason);
495	        outcomes.push({
496	          agent,
497	          proposalTitle: proposal.title,
498	          proposedChange: gateInput.proposedDiff[0],
499	          gateResults,
500	          judgeResults: null,
501	          action: "staged",
502	          reason,
503	        });
504	        continue;
505	      }
506	
507	      // Gates passed — run judges
508	      const judgeInput: JudgePanelInput = {
509	        agent,
510	        currentSoul,
511	        proposedDiff: formatProposalForJudge(proposal),
512	        evidence: proposal.evidence,
513	        gateResults,
514	      };
515	
516	      let judgeResults: JudgePanelResult;
517	      try {
518	        judgeResults = await runJudgePanel(judgeInput);
519	      } catch (err: any) {
520	        const reason = `Judge panel threw: ${err.message}`;
521	        await _stageProposal(agent, proposal, gateResults, null, reason);
522	        outcomes.push({
523	          agent,
524	          proposalTitle: proposal.title,
525	          proposedChange: gateInput.proposedDiff[0],
526	          gateResults,
527	          judgeResults: null,
528	          action: "staged",
529	          reason,
530	        });
531	        continue;
532	      }
533	
534	      if (!judgeResults.approved) {
535	        const reason = `Judges rejected: ${judgeResults.dissents.join(", ")}`;
536	        await _stageProposal(agent, proposal, gateResults, judgeResults, reason);
537	        outcomes.push({
538	          agent,
539	          proposalTitle: proposal.title,
540	          proposedChange: gateInput.proposedDiff[0],
541	          gateResults,
542	          judgeResults,
543	          action: "staged",
544	          reason,
545	        });
546	        continue;
547	      }
548	
549	      // Judges approved — apply incrementally
550	      try {
551	        applySoulChange(agent, soulPath, proposal);
552	      } catch (err: any) {
553	        const reason = `Apply failed: ${err.message}`;
554	        await _stageProposal(agent, proposal, gateResults, judgeResults, reason);
555	        outcomes.push({
556	          agent,
557	          proposalTitle: proposal.title,
558	          proposedChange: gateInput.proposedDiff[0],
559	          gateResults,
560	          judgeResults,
561	          action: "staged",
562	          reason,
563	        });
564	        continue;
565	      }
566	
567	      // Log the applied change
568	      const today = dayjs().format("YYYY-MM-DD");
569	      const linesAdded = countLines(proposal.content, proposal.type === "add");
570	      const linesRemoved = countLines(proposal.content, proposal.type === "remove");
571	
572	      try {
573	        logSoulChange({
574	          agent,
575	          date: today,
576	          linesAdded,
577	          linesRemoved,
578	          changeSummary: `[auto-applied] ${proposal.title}: ${proposal.evidence.slice(0, 200)}`,
579	          gateResults: JSON.stringify(gateResults),
580	          judgeResults: JSON.stringify(judgeResults),
581	          status: "auto-applied",
582	        });
583	      } catch {
584	        // DB log failure is non-fatal — apply already succeeded
585	      }
586	
587	      outcomes.push({
588	        agent,
589	        proposalTitle: proposal.title,
590	        proposedChange: gateInput.proposedDiff[0],
591	        gateResults,
592	        judgeResults,
593	        action: "auto-applied",
594	        reason: `Unanimous approval (${judgeResults.votes.map(v => v.model).join(", ")})`,
595	      });
596	    }
597	
598	    agentResults.push({
599	      agent,
600	      skipped: false,
601	      proposals: outcomes,
602	    });
603	  }
604	
605	  const durationMs = Date.now() - startTime;
606	  const summary = buildPipelineSummary(agentResults, durationMs);
607	
608	  return { agents: agentResults, summary };
609	}
610	
611	// ── Private: stage a proposal with appropriate logging ───────────────────────
612	
613	async function _stageProposal(
614	  agent: string,
615	  proposal: ParsedProposal,
616	  gateResults: AllGatesResult,
617	  judgeResults: JudgePanelResult | null,
618	  reason: string,
619	): Promise<void> {
620	  const today = dayjs().format("YYYY-MM-DD");
621	
622	  const stagedProposal: StagedProposal = {
623	    agent,
624	    date: today,
625	    proposedChange: proposal.title,
626	    section: proposal.section,
627	    changeType: proposal.type,
628	    evidence: proposal.evidence,
629	    gateResults,
630	    judgeResults,
631	    reason,
632	    status: "pending",
633	  };
634	
635	  try {
636	    writeStagedProposal(stagedProposal);
637	  } catch {
638	    // Stage write failure is non-fatal — pipeline continues
639	  }
640	
641	  // Log to brain.db
642	  const linesAdded = countLines(proposal.content, proposal.type === "add");
643	  const linesRemoved = countLines(proposal.content, proposal.type === "remove");
644	
645	  try {
646	    logSoulChange({
647	      agent,
648	      date: today,
649	      linesAdded,
650	      linesRemoved,
651	      changeSummary: `[staged] ${proposal.title}: ${reason.slice(0, 200)}`,
652	      gateResults: JSON.stringify(gateResults),
653	      judgeResults: judgeResults ? JSON.stringify(judgeResults) : undefined,
654	      status: "staged",
655	    });
656	  } catch {
657	    // DB log failure is non-fatal
658	  }
659	}
