/**
 * autonomous-distill.ts — End-to-end pipeline: distill → gates → judges → apply/stage
 *
 * For each agent:
 *   1. Call distillSoul (dry-run) to get proposals
 *   2. Parse proposals from text output
 *   3. For each proposal sequentially:
 *      a. Run all gates (runAllGates)
 *      b. Gates fail → writeStagedProposal + logSoulChange(staged)
 *      c. Gates pass → runJudgePanel
 *      d. Judges reject → writeStagedProposal + logSoulChange(staged)
 *      e. Judges approve → applySoulChange + logSoulChange(auto-applied)
 *
 * Proposals are applied sequentially within an agent — soul file is re-read
 * each time so changes accumulate correctly.
 *
 * fullSoul from distillSoul output is NEVER used for apply — only incremental
 * per-proposal application, so partial approval is safe.
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
import { join } from "path";
import dayjs from "./dayjs.js";
import { fromRoot } from "./paths.js";
import { runAllGates } from "./gates.js";
import type { GateInput, AllGatesResult, ProposedChange } from "./gates.js";
import { runJudgePanel } from "./judge-panel.js";
import type { JudgePanelInput, JudgePanelResult } from "./judge-panel.js";
import { writeStagedProposal } from "./staged.js";
import type { StagedProposal } from "./staged.js";
import { logSoulChange } from "./brain/queries.js";

// ── Constants ────────────────────────────────────────────────────────────────

const DISTILL_AGENTS = ["tala", "rune", "sol", "echo", "penny"];
const SOULS_DIR = fromRoot(".claude", "souls");

// ── Types ────────────────────────────────────────────────────────────────────

export interface ParsedProposal {
  title: string;
  type: "add" | "remove" | "modify";
  section: string;
  confidence: "high" | "medium";
  evidence: string;
  content: string;
}

export interface ProposalOutcome {
  agent: string;
  proposalTitle: string;
  proposedChange: ProposedChange;
  gateResults: AllGatesResult;
  judgeResults: JudgePanelResult | null;
  action: "auto-applied" | "staged";
  reason: string;
}

export interface AgentDistillResult {
  agent: string;
  skipped: boolean;
  skipReason?: string;
  proposals: ProposalOutcome[];
  error?: string;
}

export interface PipelineSummary {
  totalProposals: number;
  autoApplied: number;
  staged: number;
  skippedAgents: number;
  errors: number;
  durationMs: number;
}

export interface PipelineResult {
  agents: AgentDistillResult[];
  summary: PipelineSummary;
}

// ── Helpers ──────────────────────────────────────────────────────────────────

/** Count non-empty lines in a string. */
export function countLines(content: string, shouldCount: boolean): number {
  if (!shouldCount || !content) return 0;
  return content.split("\n").filter(l => l.trim().length > 0).length;
}

/** Human-readable diff description for the judge panel prompt. */
export function formatProposalForJudge(proposal: ParsedProposal): string {
  const lines: string[] = [];
  lines.push(`Type: ${proposal.type}`);
  lines.push(`Section: ${proposal.section}`);
  lines.push(`Confidence: ${proposal.confidence}`);
  lines.push(`Evidence: ${proposal.evidence}`);
  lines.push("");
  lines.push("Content to apply:");
  lines.push(proposal.content);
  return lines.join("\n");
}

/** Aggregate stats across all agent results. */
export function buildPipelineSummary(results: AgentDistillResult[], durationMs: number): PipelineSummary {
  let totalProposals = 0;
  let autoApplied = 0;
  let staged = 0;
  let skippedAgents = 0;
  let errors = 0;

  for (const r of results) {
    if (r.skipped) skippedAgents++;
    if (r.error) errors++;
    for (const p of r.proposals) {
      totalProposals++;
      if (p.action === "auto-applied") autoApplied++;
      else staged++;
    }
  }

  return { totalProposals, autoApplied, staged, skippedAgents, errors, durationMs };
}

/**
 * Find `## {section}` heading in content and insert `addition` before the next
 * `##` heading (or at end of file if no next heading).
 */
export function appendToSection(content: string, section: string, addition: string): string {
  const lines = content.split("\n");
  const headingPattern = new RegExp(`^##\\s+${escapeRegex(section)}\\s*$`, "i");

  let sectionStart = -1;
  for (let i = 0; i < lines.length; i++) {
    if (headingPattern.test(lines[i])) {
      sectionStart = i;
      break;
    }
  }

  if (sectionStart === -1) {
    // Section not found — append at end
    return content.trimEnd() + "\n\n" + addition.trim() + "\n";
  }

  // Find the next ## heading after sectionStart
  let insertBefore = lines.length;
  for (let i = sectionStart + 1; i < lines.length; i++) {
    if (/^##\s/.test(lines[i])) {
      insertBefore = i;
      break;
    }
  }

  // Insert addition before the next section heading (or end of file)
  const before = lines.slice(0, insertBefore);
  const after = lines.slice(insertBefore);

  // Ensure blank line before addition
  if (before.length > 0 && before[before.length - 1].trim() !== "") {
    before.push("");
  }

  const additionLines = addition.trim().split("\n");
  const result = [...before, ...additionLines, "", ...after];
  return result.join("\n");
}

function escapeRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

// ── Parse distillSoul output ─────────────────────────────────────────────────

/**
 * Parse the text output of distillSoul (dry-run) into structured proposals.
 *
 * distill-soul.ts output format (from its prompt):
 *   === PROPOSAL N: {title} ===
 *   TYPE: add | modify | remove
 *   SECTION: {section}
 *   CONFIDENCE: high | medium
 *   EVIDENCE: {text}
 *
 *   CONTENT:
 *   {actual text}
 *   === END PROPOSAL ===
 *
 * Returns empty array on NO_CHANGES or if no proposals are found.
 */
export function parseDistillOutput(output: string): ParsedProposal[] {
  if (!output || output.includes("NO_CHANGES") || output.includes("No knowledge files found")) {
    return [];
  }

  const proposals: ParsedProposal[] = [];
  const proposalRegex = /===\s*PROPOSAL\s*\d+:\s*(.*?)\s*===\n([\s\S]*?)===\s*END PROPOSAL\s*===/g;

  let match;
  while ((match = proposalRegex.exec(output)) !== null) {
    const title = match[1].trim();
    const body = match[2];

    const typeMatch = body.match(/^TYPE:\s*(\w+)/m);
    const sectionMatch = body.match(/^SECTION:\s*(.+)$/m);
    const confidenceMatch = body.match(/^CONFIDENCE:\s*(high|medium)/im);
    const evidenceMatch = body.match(/^EVIDENCE:\s*(.+)$/m);

    // CONTENT: follows "CONTENT:" and continues to === END PROPOSAL ===
    const contentMatch = body.match(/^CONTENT:\s*\n([\s\S]*)$/m);

    const rawType = typeMatch?.[1]?.toLowerCase().trim() ?? "add";
    const type: ParsedProposal["type"] =
      rawType === "remove" ? "remove" : rawType === "modify" ? "modify" : "add";

    const rawConfidence = confidenceMatch?.[1]?.toLowerCase().trim() ?? "medium";
    const confidence: ParsedProposal["confidence"] =
      rawConfidence === "high" ? "high" : "medium";

    proposals.push({
      title,
      type,
      section: sectionMatch?.[1]?.trim() ?? "",
      confidence,
      evidence: evidenceMatch?.[1]?.trim() ?? "",
      content: contentMatch?.[1]?.trim() ?? "",
    });
  }

  return proposals;
}

// ── Apply a single proposal to a soul file ────────────────────────────────────

/**
 * Apply a proposal incrementally to the soul file on disk.
 * NEVER uses fullSoul — reads from disk so changes accumulate correctly.
 *
 * "modify" is treated like "add" — content is appended to the target section
 * (non-destructive). Gate 2 (size) applies the same 3-line budget to both.
 */
export function applySoulChange(
  agent: string,
  soulPath: string,
  proposal: ParsedProposal,
): void {
  if (!existsSync(soulPath)) {
    throw new Error(`Soul file not found: ${soulPath}`);
  }

  const current = readFileSync(soulPath, "utf-8");

  if (proposal.type === "add" || proposal.type === "modify") {
    if (!proposal.content) {
      throw new Error(`${proposal.type} proposal "${proposal.title}" has no content`);
    }
    const updated = appendToSection(current, proposal.section, proposal.content);
    writeFileSync(soulPath, updated, "utf-8");
    return;
  }

  if (proposal.type === "remove") {
    if (!proposal.content) {
      throw new Error(`remove proposal "${proposal.title}" has no content to match for removal`);
    }
    // Remove matching content from the file; clean up extra blank lines
    const normalized = current.replace(/\r\n/g, "\n");
    const target = proposal.content.trim();
    if (!normalized.includes(target)) {
      throw new Error(`remove proposal "${proposal.title}": content not found in soul file`);
    }
    const updated = normalized.replace(target, "").replace(/\n{3,}/g, "\n\n");
    writeFileSync(soulPath, updated, "utf-8");
    return;
  }
}

// ── Write pipeline summary to out/ ───────────────────────────────────────────

export function writePipelineSummary(result: PipelineResult): string {
  const outDir = fromRoot("out");
  mkdirSync(outDir, { recursive: true });

  const summaryPath = join(outDir, "autonomous-distill-summary.md");
  const now = dayjs().format("YYYY-MM-DD HH:mm:ss");

  const lines: string[] = [];
  lines.push("# Autonomous Distill Summary");
  lines.push("");
  lines.push(`Run: ${now}`);
  lines.push(`Duration: ${result.summary.durationMs}ms`);
  lines.push("");
  lines.push("## Summary");
  lines.push("");
  lines.push(`| Metric | Count |`);
  lines.push(`|--------|-------|`);
  lines.push(`| Total proposals | ${result.summary.totalProposals} |`);
  lines.push(`| Auto-applied | ${result.summary.autoApplied} |`);
  lines.push(`| Staged | ${result.summary.staged} |`);
  lines.push(`| Skipped agents | ${result.summary.skippedAgents} |`);
  lines.push(`| Errors | ${result.summary.errors} |`);
  lines.push("");
  lines.push("## Per-Agent Results");
  lines.push("");

  for (const agentResult of result.agents) {
    lines.push(`### ${agentResult.agent}`);
    lines.push("");

    if (agentResult.skipped) {
      lines.push(`Skipped: ${agentResult.skipReason ?? "unknown reason"}`);
      lines.push("");
      continue;
    }

    if (agentResult.error) {
      lines.push(`Error: ${agentResult.error}`);
      lines.push("");
    }

    if (agentResult.proposals.length === 0) {
      lines.push("No proposals processed.");
      lines.push("");
      continue;
    }

    for (const p of agentResult.proposals) {
      lines.push(`#### ${p.proposalTitle}`);
      lines.push("");
      lines.push(`Action: **${p.action}**`);
      lines.push(`Reason: ${p.reason}`);
      lines.push("");

      lines.push("Gates:");
      for (const g of p.gateResults.results) {
        lines.push(`- ${g.gate}: ${g.pass ? "PASS" : "FAIL"} — ${g.reason}`);
      }
      lines.push("");

      if (p.judgeResults) {
        lines.push("Judges:");
        for (const v of p.judgeResults.votes) {
          lines.push(`- ${v.model}: ${v.vote} — ${v.reason}`);
        }
        lines.push("");
      }
    }
  }

  writeFileSync(summaryPath, lines.join("\n"), "utf-8");
  return summaryPath;
}

// ── Main pipeline ─────────────────────────────────────────────────────────────

/**
 * Run the full autonomous distill pipeline for the given agents (or all DISTILL_AGENTS).
 *
 * For each agent:
 *   1. Call distillSoul in dry-run mode
 *   2. Parse proposals
 *   3. For each proposal (sequential — soul changes build on each other):
 *      a. Read current soul from disk
 *      b. Run gates
 *      c. If gates fail → stage + log
 *      d. If gates pass → run judges
 *      e. If judges reject → stage + log
 *      f. If judges approve → apply + log
 *
 * Per-agent errors are caught and reported — they do not crash the pipeline.
 */
export async function autonomousDistill(agents?: string[]): Promise<PipelineResult> {
  const startTime = Date.now();
  const targetAgents = agents && agents.length > 0
    ? agents.filter(a => DISTILL_AGENTS.includes(a))
    : DISTILL_AGENTS;

  const agentResults: AgentDistillResult[] = [];

  for (const agent of targetAgents) {
    const soulPath = join(SOULS_DIR, `${agent}.md`);

    // Validate soul file exists
    if (!existsSync(soulPath)) {
      agentResults.push({
        agent,
        skipped: true,
        skipReason: `Soul file not found: ${soulPath}`,
        proposals: [],
      });
      continue;
    }

    let rawDistillOutput: string;
    try {
      const { callDistillGemini } = await import("../tools/distill-soul.js");
      const result = await callDistillGemini(agent);

      if (result.noChanges) {
        agentResults.push({
          agent,
          skipped: true,
          skipReason: result.skipReason ?? "No proposals",
          proposals: [],
        });
        continue;
      }

      rawDistillOutput = result.rawOutput;
    } catch (err: any) {
      agentResults.push({
        agent,
        skipped: false,
        proposals: [],
        error: `distillSoul failed: ${err.message?.split("\n")[0] ?? "unknown"}`,
      });
      continue;
    }

    const parsedProposals = parseDistillOutput(rawDistillOutput);

    if (parsedProposals.length === 0) {
      agentResults.push({
        agent,
        skipped: true,
        skipReason: "No proposals from distillSoul (NO_CHANGES or parse returned empty)",
        proposals: [],
      });
      continue;
    }

    const outcomes: ProposalOutcome[] = [];

    for (const proposal of parsedProposals) {
      // Re-read soul file each iteration — prior proposals may have modified it
      let currentSoul: string;
      try {
        currentSoul = readFileSync(soulPath, "utf-8");
      } catch (err: any) {
        outcomes.push({
          agent,
          proposalTitle: proposal.title,
          proposedChange: {
            type: proposal.type,
            section: proposal.section,
            content: proposal.content,
            evidence: proposal.evidence,
          },
          gateResults: { passed: false, results: [], failedGates: ["read-error"] },
          judgeResults: null,
          action: "staged",
          reason: `Could not read soul file: ${err.message}`,
        });
        continue;
      }

      // Build gate input
      const gateInput: GateInput = {
        agent,
        currentSoul,
        proposedDiff: [
          {
            type: proposal.type,
            section: proposal.section,
            content: proposal.content,
            evidence: proposal.evidence,
          },
        ],
      };

      let gateResults: AllGatesResult;
      try {
        gateResults = await runAllGates(gateInput);
      } catch (err: any) {
        // Gate system failure — stage defensively
        const emptyGateResult: AllGatesResult = {
          passed: false,
          results: [],
          failedGates: ["gate-error"],
        };
        await _stageProposal(agent, proposal, emptyGateResult, null, `Gates threw: ${err.message}`);
        outcomes.push({
          agent,
          proposalTitle: proposal.title,
          proposedChange: gateInput.proposedDiff[0],
          gateResults: emptyGateResult,
          judgeResults: null,
          action: "staged",
          reason: `Gate system error: ${err.message}`,
        });
        continue;
      }

      if (!gateResults.passed) {
        const reason = `Gates failed: ${gateResults.failedGates.join(", ")}`;
        await _stageProposal(agent, proposal, gateResults, null, reason);
        outcomes.push({
          agent,
          proposalTitle: proposal.title,
          proposedChange: gateInput.proposedDiff[0],
          gateResults,
          judgeResults: null,
          action: "staged",
          reason,
        });
        continue;
      }

      // Gates passed — run judges
      const judgeInput: JudgePanelInput = {
        agent,
        currentSoul,
        proposedDiff: formatProposalForJudge(proposal),
        evidence: proposal.evidence,
        gateResults,
      };

      let judgeResults: JudgePanelResult;
      try {
        judgeResults = await runJudgePanel(judgeInput);
      } catch (err: any) {
        const reason = `Judge panel threw: ${err.message}`;
        await _stageProposal(agent, proposal, gateResults, null, reason);
        outcomes.push({
          agent,
          proposalTitle: proposal.title,
          proposedChange: gateInput.proposedDiff[0],
          gateResults,
          judgeResults: null,
          action: "staged",
          reason,
        });
        continue;
      }

      if (!judgeResults.approved) {
        const reason = `Judges rejected: ${judgeResults.dissents.join(", ")}`;
        await _stageProposal(agent, proposal, gateResults, judgeResults, reason);
        outcomes.push({
          agent,
          proposalTitle: proposal.title,
          proposedChange: gateInput.proposedDiff[0],
          gateResults,
          judgeResults,
          action: "staged",
          reason,
        });
        continue;
      }

      // Judges approved — apply incrementally
      try {
        applySoulChange(agent, soulPath, proposal);
      } catch (err: any) {
        const reason = `Apply failed: ${err.message}`;
        await _stageProposal(agent, proposal, gateResults, judgeResults, reason);
        outcomes.push({
          agent,
          proposalTitle: proposal.title,
          proposedChange: gateInput.proposedDiff[0],
          gateResults,
          judgeResults,
          action: "staged",
          reason,
        });
        continue;
      }

      // Log the applied change
      const today = dayjs().format("YYYY-MM-DD");
      const linesAdded = countLines(proposal.content, proposal.type === "add");
      const linesRemoved = countLines(proposal.content, proposal.type === "remove");

      try {
        logSoulChange({
          agent,
          date: today,
          linesAdded,
          linesRemoved,
          changeSummary: `[auto-applied] ${proposal.title}: ${proposal.evidence.slice(0, 200)}`,
          gateResults: JSON.stringify(gateResults),
          judgeResults: JSON.stringify(judgeResults),
          status: "auto-applied",
        });
      } catch {
        // DB log failure is non-fatal — apply already succeeded
      }

      outcomes.push({
        agent,
        proposalTitle: proposal.title,
        proposedChange: gateInput.proposedDiff[0],
        gateResults,
        judgeResults,
        action: "auto-applied",
        reason: `Unanimous approval (${judgeResults.votes.map(v => v.model).join(", ")})`,
      });
    }

    agentResults.push({
      agent,
      skipped: false,
      proposals: outcomes,
    });
  }

  const durationMs = Date.now() - startTime;
  const summary = buildPipelineSummary(agentResults, durationMs);

  return { agents: agentResults, summary };
}

// ── Private: stage a proposal with appropriate logging ───────────────────────

async function _stageProposal(
  agent: string,
  proposal: ParsedProposal,
  gateResults: AllGatesResult,
  judgeResults: JudgePanelResult | null,
  reason: string,
): Promise<void> {
  const today = dayjs().format("YYYY-MM-DD");

  const stagedProposal: StagedProposal = {
    agent,
    date: today,
    proposedChange: proposal.title,
    section: proposal.section,
    changeType: proposal.type,
    evidence: proposal.evidence,
    gateResults,
    judgeResults,
    reason,
    status: "pending",
  };

  try {
    writeStagedProposal(stagedProposal);
  } catch {
    // Stage write failure is non-fatal — pipeline continues
  }

  // Log to brain.db
  const linesAdded = countLines(proposal.content, proposal.type === "add");
  const linesRemoved = countLines(proposal.content, proposal.type === "remove");

  try {
    logSoulChange({
      agent,
      date: today,
      linesAdded,
      linesRemoved,
      changeSummary: `[staged] ${proposal.title}: ${reason.slice(0, 200)}`,
      gateResults: JSON.stringify(gateResults),
      judgeResults: judgeResults ? JSON.stringify(judgeResults) : undefined,
      status: "staged",
    });
  } catch {
    // DB log failure is non-fatal
  }
}

