214	    ? readdirSync(sharedKnowledgeDir).filter(f => f.endsWith(".md")).length > 0
215	    : false;
216	
217	  out.push(`=== SOUL DISTILLATION: ${agent} ===`);
218	  out.push(`  Soul: ${soulPath}`);
219	  out.push(`  Knowledge: ${agentKnowledge ? "yes" : "none"} (agent), ${sharedKnowledge ? "yes" : "none"} (shared)`);
