/**
 * gates.ts — Validation gates for soul file changes
 *
 * 5 gates run in order (cheapest first):
 *   1. safety    — deterministic: block changes to protected sections
 *   2. size      — deterministic: max 6 added/modified lines, 1 removed
 *   3. drift     — deterministic: DB query, cumulative 30-day change limit
 *   4. regression — embeddings + optional Gemini: contradiction detection
 *   5. constitution — Gemini LLM call: identity alignment check
 *
 * All 5 gates always run (no short-circuit) — full results for human review.
 */

import { generateText } from "./gemini.js";
import { embedText, embedBatch } from "./embeddings.js";
import { querySoulDrift } from "./brain/queries.js";

// ── Types ────────────────────────────────────────────────────────────────────

export interface GateResult {
  gate: string;   // "constitution" | "regression" | "size" | "drift" | "safety"
  pass: boolean;
  reason: string;
}

export interface GateInput {
  agent: string;
  currentSoul: string;
  proposedDiff: ProposedChange[];
}

export interface ProposedChange {
  type: "add" | "remove" | "modify";
  section: string;
  content: string;
  evidence: string;
}

export interface AllGatesResult {
  passed: boolean;
  results: GateResult[];
  failedGates: string[];
}

// ── Protected section names (case-insensitive) ──────────────────────────────

const PROTECTED_SECTION_NAMES = [
  "who i am",
  "who you are",
  "creative philosophy",
  "hard rules",
  "the line i won't cross",
  "my line",
  "core identity",
];

// ── Helper: cosine similarity ────────────────────────────────────────────────

export function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length === 0 || b.length === 0 || a.length !== b.length) return 0;
  let dot = 0;
  let magA = 0;
  let magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

// ── Helper: parse protected sections from soul text ──────────────────────────

/**
 * Returns a Set of lowercase section names that are protected.
 * Protected = named in PROTECTED_SECTION_NAMES or contains <!-- protected -->.
 */
function parseProtectedSections(soulText: string): Set<string> {
  const protected_ = new Set<string>();
  const lines = soulText.split("\n");
  let currentSection = "";
  let sectionLines: string[] = [];

  function flushSection() {
    if (!currentSection) return;
    const nameLower = currentSection.toLowerCase();
    if (PROTECTED_SECTION_NAMES.includes(nameLower)) {
      protected_.add(nameLower);
    } else if (sectionLines.some(l => l.includes("<!-- protected -->"))) {
      protected_.add(nameLower);
    }
  }

  for (const line of lines) {
    const headingMatch = line.match(/^#{1,6}\s+(.+)$/);
    if (headingMatch) {
      flushSection();
      currentSection = headingMatch[1].trim();
      sectionLines = [];
    } else {
      sectionLines.push(line);
    }
  }
  flushSection();

  return protected_;
}

// ── Helper: extract rule-like sentences from soul text ──────────────────────

/**
 * Returns lines that look like rules: list items, lines with modal verbs,
 * or lines inside Hard Rules / Core Opinions / Postmortem Reflexes sections.
 */
function extractRuleSentences(soulText: string): string[] {
  const rules: string[] = [];
  const lines = soulText.split("\n");
  const ruleHeaders = ["hard rules", "core opinions", "postmortem reflexes"];
  let inRuleSection = false;

  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;

    // Check for section heading
    const headingMatch = trimmed.match(/^#{1,6}\s+(.+)$/);
    if (headingMatch) {
      inRuleSection = ruleHeaders.includes(headingMatch[1].toLowerCase());
      continue;
    }

    // Collect from rule sections unconditionally
    if (inRuleSection) {
      rules.push(trimmed);
      continue;
    }

    // List items (-, *, numbered)
    if (/^[-*]\s+.+/.test(trimmed) || /^\d+\.\s+.+/.test(trimmed)) {
      rules.push(trimmed);
      continue;
    }

    // Lines with modal verbs
    if (/\b(always|never|must|don't|do not)\b/i.test(trimmed)) {
      rules.push(trimmed);
      continue;
    }
  }

  return rules;
}

// ── Gate 1: Safety ───────────────────────────────────────────────────────────

/**
 * Gate 1 (cheapest): Block any changes targeting protected sections.
 * Fully deterministic — no LLM, no DB.
 */
async function runSafetyGate(input: GateInput): Promise<GateResult> {
  if (!input.currentSoul || typeof input.currentSoul !== "string") {
    return { gate: "safety", pass: false, reason: "currentSoul is empty or invalid" };
  }
  if (!input.proposedDiff || input.proposedDiff.length === 0) {
    return { gate: "safety", pass: true, reason: "No proposed changes — nothing to check" };
  }

  const protected_ = parseProtectedSections(input.currentSoul);
  if (protected_.size === 0) {
    return { gate: "safety", pass: true, reason: "No protected sections found in soul file" };
  }

  const violations: string[] = [];
  for (const change of input.proposedDiff) {
    const sectionLower = (change.section ?? "").toLowerCase().trim();
    if (protected_.has(sectionLower)) {
      violations.push(`"${change.section}" is a protected section`);
    }
  }

  if (violations.length > 0) {
    return {
      gate: "safety",
      pass: false,
      reason: `Changes target protected sections: ${violations.join("; ")}`,
    };
  }

  return { gate: "safety", pass: true, reason: "No changes target protected sections" };
}

// ── Gate 2: Size ─────────────────────────────────────────────────────────────

/**
 * Gate 2: Enforce per-cycle line budget.
 * Max 6 added/modified lines, max 1 removed.
 * modify is treated like add — content is appended to the target section (non-destructive).
 * Fully deterministic — no LLM, no DB.
 */
async function runSizeGate(input: GateInput): Promise<GateResult> {
  if (!input.proposedDiff || input.proposedDiff.length === 0) {
    return { gate: "size", pass: true, reason: "No proposed changes" };
  }

  const addedLines = input.proposedDiff
    .filter(c => c.type === "add" || c.type === "modify")
    .reduce((sum, c) => sum + (c.content ? c.content.split("\n").length : 0), 0);

  const removedCount = input.proposedDiff.filter(c => c.type === "remove").length;

  const failures: string[] = [];
  if (addedLines > 6) {
    failures.push(`${addedLines} lines added/modified (max 6)`);
  }
  if (removedCount > 1) {
    failures.push(`${removedCount} removals (max 1)`);
  }

  if (failures.length > 0) {
    return { gate: "size", pass: false, reason: failures.join("; ") };
  }

  return {
    gate: "size",
    pass: true,
    reason: `${addedLines} lines added/modified, ${removedCount} removed — within limits`,
  };
}

// ── Gate 3: Drift ────────────────────────────────────────────────────────────

/**
 * Gate 3: Block if cumulative 30-day changes exceed 10% of soul file line count.
 * Reads soul_changes table via querySoulDrift().
 */
async function runDriftGate(input: GateInput): Promise<GateResult> {
  if (!input.currentSoul || typeof input.currentSoul !== "string") {
    return { gate: "drift", pass: false, reason: "currentSoul is empty — cannot compute soul line count" };
  }

  const soulLineCount = input.currentSoul.split("\n").length;
  if (soulLineCount === 0) {
    return { gate: "drift", pass: false, reason: "Soul file appears empty" };
  }

  const threshold = Math.ceil(soulLineCount * 0.1);

  let drift: { added: number; removed: number };
  try {
    drift = querySoulDrift(input.agent, 30);
  } catch (err: any) {
    // DB not initialized or table missing — allow through (drift is unknown)
    return {
      gate: "drift",
      pass: true,
      reason: `Drift query failed (${err.message}) — allowing through`,
    };
  }

  // Add the lines this proposed change would add/remove
  const proposedAdded = (input.proposedDiff ?? [])
    .filter(c => c.type === "add")
    .reduce((sum, c) => sum + (c.content ? c.content.split("\n").length : 0), 0);
  const proposedRemoved = (input.proposedDiff ?? []).filter(c => c.type === "remove").length;

  const totalAdded = drift.added + proposedAdded;
  const totalRemoved = drift.removed + proposedRemoved;
  const totalChange = totalAdded + totalRemoved;

  if (totalChange > threshold) {
    return {
      gate: "drift",
      pass: false,
      reason: `Cumulative 30-day changes (${totalChange} lines) exceed 10% threshold (${threshold} lines) of soul file (${soulLineCount} lines)`,
    };
  }

  return {
    gate: "drift",
    pass: true,
    reason: `30-day drift ${totalChange}/${threshold} (${soulLineCount}-line soul, 10% threshold)`,
  };
}

// ── Gate 4: Regression ───────────────────────────────────────────────────────

const REGRESSION_SIMILARITY_THRESHOLD = 0.85;

/**
 * Gate 4: Detect regressions by embedding proposed changes against existing rules.
 * If cosine similarity > 0.85, calls Gemini to confirm contradiction.
 */
async function runRegressionGate(input: GateInput): Promise<GateResult> {
  if (!input.proposedDiff || input.proposedDiff.length === 0) {
    return { gate: "regression", pass: true, reason: "No proposed changes" };
  }
  if (!input.currentSoul || typeof input.currentSoul !== "string") {
    return { gate: "regression", pass: false, reason: "currentSoul is empty — cannot extract rules" };
  }

  const rules = extractRuleSentences(input.currentSoul);
  if (rules.length === 0) {
    return { gate: "regression", pass: true, reason: "No rule sentences found in soul — skipping regression check" };
  }

  // Build change texts
  const changeParts = input.proposedDiff
    .filter(c => c.content?.trim())
    .map(c => `[${c.type}] ${c.content.trim()}`);

  if (changeParts.length === 0) {
    return { gate: "regression", pass: true, reason: "No change content to embed" };
  }

  // Embed rules and changes
  let ruleEmbeddings: (number[] | null)[];
  let changeEmbeddings: (number[] | null)[];

  try {
    const [ruleResult, changeResult] = await Promise.all([
      embedBatch(rules, "gate-regression"),
      embedBatch(changeParts, "gate-regression"),
    ]);
    ruleEmbeddings = ruleResult.embeddings;
    changeEmbeddings = changeResult.embeddings;
  } catch (err: any) {
    // Embedding failure is non-fatal — degrade gracefully
    return {
      gate: "regression",
      pass: true,
      reason: `Embedding unavailable (${err.message}) — regression check skipped`,
    };
  }

  // Check each change against each rule for high similarity
  const contradictions: string[] = [];
  for (let ci = 0; ci < changeParts.length; ci++) {
    const changeEmb = changeEmbeddings[ci];
    if (!changeEmb) continue;

    for (let ri = 0; ri < rules.length; ri++) {
      const ruleEmb = ruleEmbeddings[ri];
      if (!ruleEmb) continue;

      const sim = cosineSimilarity(changeEmb, ruleEmb);
      if (sim > REGRESSION_SIMILARITY_THRESHOLD) {
        // High similarity — ask Gemini to confirm
        let isContradiction = false;
        try {
          const prompt = [
            `You are reviewing a proposed soul file change against an existing rule.`,
            ``,
            `Existing rule: ${rules[ri]}`,
            `Proposed change: ${changeParts[ci]}`,
            ``,
            `Does the proposed change CONTRADICT the existing rule, or is it COMPATIBLE?`,
            `Reply with exactly one word: CONTRADICTION or COMPATIBLE`,
          ].join("\n");

          const result = await generateText(prompt, {
            model: "gemini-2.5-flash",
            temperature: 0.2,
            maxOutputTokens: 256,
            caller: "gate-regression",
          });

          isContradiction = result.text.trim().toUpperCase().startsWith("CONTRADICTION");
        } catch {
          // Gemini failure — assume contradiction when similarity is very high
          isContradiction = sim > 0.92;
        }

        if (isContradiction) {
          contradictions.push(
            `Change "${changeParts[ci].slice(0, 60)}..." contradicts rule "${rules[ri].slice(0, 60)}..." (similarity ${sim.toFixed(2)})`
          );
        }
      }
    }
  }

  if (contradictions.length > 0) {
    return {
      gate: "regression",
      pass: false,
      reason: contradictions.join("; "),
    };
  }

  return { gate: "regression", pass: true, reason: "No rule contradictions detected" };
}

// ── Gate 5: Constitution ─────────────────────────────────────────────────────

/**
 * Gate 5: LLM identity check — does the proposed change contradict agent identity?
 * Uses Gemini 2.5 Flash with low temperature.
 */
async function runConstitutionGate(input: GateInput): Promise<GateResult> {
  if (!input.proposedDiff || input.proposedDiff.length === 0) {
    return { gate: "constitution", pass: true, reason: "No proposed changes" };
  }
  if (!input.currentSoul || typeof input.currentSoul !== "string") {
    return { gate: "constitution", pass: false, reason: "currentSoul is empty — cannot assess identity alignment" };
  }

  const changeSummary = input.proposedDiff
    .map(c => `[${c.type} in "${c.section}"]: ${c.content}`)
    .join("\n");

  const prompt = [
    `You are a guardian reviewing a proposed change to an AI agent's soul file.`,
    `The soul file defines the agent's identity, values, and behavioral constraints.`,
    ``,
    `Agent: ${input.agent}`,
    ``,
    `Current soul file (excerpt — first 2000 chars):`,
    input.currentSoul.slice(0, 2000),
    ``,
    `Proposed changes:`,
    changeSummary,
    ``,
    `Does any proposed change contradict the agent's core identity or values?`,
    `Reply starting with PASS if all changes are consistent with identity,`,
    `or FAIL followed by a brief reason if any change contradicts identity.`,
  ].join("\n");

  try {
    const result = await generateText(prompt, {
      model: "gemini-2.5-flash",
      temperature: 0.2,
      maxOutputTokens: 256,
      caller: "gate-constitution",
    });

    const responseText = result.text.trim();
    if (responseText.toUpperCase().startsWith("PASS")) {
      return { gate: "constitution", pass: true, reason: responseText };
    }
    if (responseText.toUpperCase().startsWith("FAIL")) {
      return { gate: "constitution", pass: false, reason: responseText };
    }

    // Ambiguous response — treat as fail (strict default)
    return {
      gate: "constitution",
      pass: false,
      reason: `Ambiguous Gemini response (neither PASS nor FAIL): ${responseText.slice(0, 200)}`,
    };
  } catch (err: any) {
    // Gemini unavailable — fail the gate (constitution check is required)
    return {
      gate: "constitution",
      pass: false,
      reason: `Gemini unavailable: ${err.message}`,
    };
  }
}

// ── Orchestrator ─────────────────────────────────────────────────────────────

/**
 * Run all 5 gates in order: safety, size, drift, regression, constitution.
 * All gates always run — no short-circuit — to collect full results for human review.
 *
 * @param input - Agent name, current soul text, proposed changes
 * @returns Combined result with per-gate results and overall pass/fail
 */
export async function runAllGates(input: GateInput): Promise<AllGatesResult> {
  if (!input || !input.agent || typeof input.agent !== "string") {
    throw new Error("runAllGates: input.agent is required");
  }
  if (!input.currentSoul || typeof input.currentSoul !== "string") {
    throw new Error("runAllGates: input.currentSoul is required");
  }
  if (!Array.isArray(input.proposedDiff)) {
    throw new Error("runAllGates: input.proposedDiff must be an array");
  }

  // Run all gates (never short-circuit)
  const [safety, size, drift, regression, constitution] = await Promise.allSettled([
    runSafetyGate(input),
    runSizeGate(input),
    runDriftGate(input),
    runRegressionGate(input),
    runConstitutionGate(input),
  ]);

  // Unwrap settled results — a gate rejection counts as a fail
  function unwrap(settled: PromiseSettledResult<GateResult>, gateName: string): GateResult {
    if (settled.status === "fulfilled") return settled.value;
    return {
      gate: gateName,
      pass: false,
      reason: `Gate threw unexpectedly: ${settled.reason?.message ?? settled.reason}`,
    };
  }

  const results: GateResult[] = [
    unwrap(safety, "safety"),
    unwrap(size, "size"),
    unwrap(drift, "drift"),
    unwrap(regression, "regression"),
    unwrap(constitution, "constitution"),
  ];

  const failedGates = results.filter(r => !r.pass).map(r => r.gate);

  return {
    passed: failedGates.length === 0,
    results,
    failedGates,
  };
}
